function centroid(points: number[][]) {
    let signedArea = 0;
    let cx = 0;
    let cy = 0;
    const len = points.length;
    let x0 = points[len - 1][0];
    let y0 = points[len - 1][1];
    // Polygon should been closed.
    for (let i = 0; i < len; i++) {
        const x1 = points[i][0];
        const y1 = points[i][1];
        const a = x0 * y1 - x1 * y0;
        signedArea += a;
        cx += (x0 + x1) * a;
        cy += (y0 + y1) * a;
        x0 = x1;
        y0 = y1;
    }

    return signedArea
        ? [cx / signedArea / 3, cy / signedArea / 3, signedArea]
